// -- COVER COMPONENT -----------------------------------------------------------
function CoverImg({
  cover,
  height = 110,
  coverColor,
  labelColor,
  customLabel,
  children,
}) {
  const id = typeof cover === "string" ? cover : "house";
  const cv = COVERS.find((c) => c.id === id) || COVERS[0];
  const bg = coverColor || cv.bg;
  const label =
    customLabel !== undefined && customLabel !== null && customLabel !== ""
      ? customLabel
      : cv.label;
  // Text always white — covers are designed to support it
  const txtColor = "rgba(255,255,255,0.95)";
  return (
    <div
      style={{
        height,
        position: "relative",
        overflow: "hidden",
        background: bg,
      }}
    >
      <div
        style={{
          position: "absolute",
          inset: 0,
          background:
            "linear-gradient(to top,rgba(0,0,0,0.30) 0%,rgba(0,0,0,0.08) 100%)",
        }}
      />
      <div
        style={{
          position: "absolute",
          inset: 0,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          zIndex: 1,
        }}
      >
        <span
          style={{
            color: txtColor,
            fontSize: Math.max(12, height * 0.28),
            fontWeight: "800",
            letterSpacing: "-0.5px",
            textShadow: "0 1px 8px rgba(0,0,0,0.5)",
            userSelect: "none",
            textAlign: "center",
            padding: "0 12px",
            lineHeight: 1.1,
          }}
        >
          {label}
        </span>
      </div>
      {children}
    </div>
  );
}

