function CurrencySearch({ currency, currencies, onSelect }) {
  const [q, setQ] = useState("");
  const [open, setOpen] = useState(false);
  const current = CURRENCY_SEARCH_DATA.find((c) => c.code === currency);

  const filtered =
    q.trim().length > 0
      ? CURRENCY_SEARCH_DATA.filter((c) => {
          const s = q.toLowerCase();
          return (
            c.code.toLowerCase().includes(s) ||
            c.label.toLowerCase().includes(s) ||
            c.keywords.includes(s)
          );
        }).slice(0, 6)
      : [];

  return (
    <div style={{ position: "relative" }}>
      <div
        style={{
          display: "flex",
          gap: "8px",
          alignItems: "center",
          padding: "10px 12px",
          border: "1.5px solid var(--border)",
          borderRadius: "var(--radius-sm)",
          background: "white",
          cursor: "text",
        }}
        onClick={() => setOpen(true)}
      >
        <span style={{ fontSize: "20px", lineHeight: 1 }}>
          {current?.flag || "🏳️"}
        </span>
        <span
          style={{
            fontFamily: "var(--mono)",
            fontWeight: "700",
            color: "var(--accent)",
            fontSize: "14px",
          }}
        >
          {currency}
        </span>
        <span style={{ fontSize: "12px", color: "var(--text2)", flex: 1 }}>
          {current?.label.split("—")[1]?.trim() || ""}
        </span>
        <span style={{ fontSize: "11px", color: "var(--text3)" }}>▼</span>
      </div>
      {open && (
        <div
          style={{
            position: "absolute",
            top: "calc(100% + 4px)",
            left: 0,
            right: 0,
            zIndex: 50,
            background: "white",
            border: "1.5px solid var(--border)",
            borderRadius: "var(--radius-sm)",
            boxShadow: "0 8px 24px rgba(0,0,0,0.12)",
          }}
        >
          <div style={{ padding: "8px" }}>
            <input
              autoFocus
              placeholder="Search country or currency..."
              value={q}
              onChange={(e) => setQ(e.target.value)}
              style={{
                width: "100%",
                padding: "9px 12px",
                border: "1.5px solid var(--border)",
                borderRadius: "8px",
                fontSize: "13px",
                fontFamily: "inherit",
                outline: "none",
                boxSizing: "border-box",
              }}
            />
          </div>
          {filtered.length > 0 && (
            <div style={{ maxHeight: "220px", overflowY: "auto" }}>
              {filtered.map((c) => (
                <div
                  key={c.code}
                  onClick={() => {
                    onSelect(c.code);
                    setQ("");
                    setOpen(false);
                  }}
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: "10px",
                    padding: "10px 12px",
                    cursor: "pointer",
                    borderTop: "1px solid var(--border)",
                    background:
                      c.code === currency ? "var(--accent-light)" : "white",
                  }}
                  onMouseEnter={(e) =>
                    (e.currentTarget.style.background = "var(--bg)")
                  }
                  onMouseLeave={(e) =>
                    (e.currentTarget.style.background =
                      c.code === currency ? "var(--accent-light)" : "white")
                  }
                >
                  <span style={{ fontSize: "20px", lineHeight: 1 }}>
                    {c.flag || "🏳️"}
                  </span>
                  <span
                    style={{
                      fontFamily: "var(--mono)",
                      fontWeight: "700",
                      color: "var(--accent)",
                      fontSize: "13px",
                      minWidth: "36px",
                    }}
                  >
                    {c.code}
                  </span>
                  <span style={{ fontSize: "12px", color: "var(--text2)" }}>
                    {c.label.split("—")[1]?.trim() || c.label}
                  </span>
                </div>
              ))}
            </div>
          )}
          {q.trim().length > 0 && filtered.length === 0 && (
            <div
              style={{
                padding: "12px",
                fontSize: "12px",
                color: "var(--text3)",
                textAlign: "center",
              }}
            >
              No results for "{q}"
            </div>
          )}
          {q.trim().length === 0 && (
            <div
              style={{
                padding: "12px",
                fontSize: "12px",
                color: "var(--text3)",
                textAlign: "center",
              }}
            >
              Type a country name or currency code
            </div>
          )}
          <div style={{ padding: "8px", borderTop: "1px solid var(--border)" }}>
            <button
              className="btn btn-secondary"
              style={{ width: "100%", fontSize: "12px", padding: "7px" }}
              onClick={() => {
                setOpen(false);
                setQ("");
              }}
            >
              Close
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

function ProfileModal({
  user,
  ledgers = [],
  onLedgersRefresh,
  onClose,
  onUpdate,
  onLogout,
  onDelete,
  currency = "RSD",
  onCurrencyChange,
  currencies = [],
  userPlan,
  onShowUpgrade,
}) {
  const plan = userPlan || PLANS.free;
  const [name, setName] = useState(user.full_name);
  const [email, setEmail] = useState(user.email);
  const [dob, setDob] = useState(user.date_of_birth || user.dob || "");
  const [selectedAvatar, setSelectedAvatar] = useState(user.avatar || null);
  const [showAvatarPicker, setShowAvatarPicker] = useState(false);
  const [saved, setSaved] = useState(false);
  // Password change
  const [showPwdSection, setShowPwdSection] = useState(false);
  const [pwdCurrent, setPwdCurrent] = useState("");
  const [pwdNew, setPwdNew] = useState("");
  const [pwdNew2, setPwdNew2] = useState("");
  const [showPwd, setShowPwd] = useState(false);
  const [pwdMsg, setPwdMsg] = useState("");
  // Delete account
  const [showDelete, setShowDelete] = useState(false);
  const [deleteWord, setDeleteWord] = useState("");
  const [deleteScheduled, setDeleteScheduled] = useState(
    user.deleteScheduled || null
  );
  const [pushStatus, setPushStatus] = useState("checking"); // checking | unsupported | default | granted | denied | enabling
  useEffect(() => {
    if (
      !("Notification" in window) ||
      !("serviceWorker" in navigator) ||
      !("PushManager" in window)
    ) {
      setPushStatus("unsupported");
      return;
    }
    setPushStatus(Notification.permission); // "default" | "granted" | "denied"
  }, []);
  const handleEnablePush = async () => {
    setPushStatus("enabling");
    const res = await enablePushNotifications(user.id);
    setPushStatus(
      res.ok ? "granted" : res.reason === "denied" ? "denied" : "default"
    );
  };

  const save = async () => {
    const updated = {
      ...user,
      full_name: name,
      email,
      date_of_birth: dob || null,
      avatar: selectedAvatar,
    };
    onUpdate(updated);
    // Persist to Supabase
    if (ENV === "production") {
      const { error: profErr } = await sb
        .from("profiles")
        .upsert({
          id: user.id,
          full_name: name || null,
          email: email || null,
          avatar: selectedAvatar || null,
          date_of_birth: dob || null,
        })
        .eq("id", user.id);
      if (profErr) console.error("Profile save error:", profErr);
      // Sync display_name on all ledger_members where this user is a member
      await sb
        .from("ledger_members")
        .update({
          display_name: name || null,
        })
        .eq("user_id", user.id);
    }
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  const changePassword = async () => {
    if (!pwdCurrent) {
      setPwdMsg("Enter current password.");
      return;
    }
    if (pwdNew.length < 6) {
      setPwdMsg("New password must be at least 6 characters.");
      return;
    }
    if (pwdNew !== pwdNew2) {
      setPwdMsg("Passwords don't match.");
      return;
    }
    if (ENV === "production") {
      const { error } = await sb.auth.updateUser({ password: pwdNew });
      if (error) {
        setPwdMsg(error.message);
        return;
      }
    }
    setPwdMsg("Password changed successfully!");
    setPwdCurrent("");
    setPwdNew("");
    setPwdNew2("");
    setTimeout(() => {
      setPwdMsg("");
      setShowPwdSection(false);
    }, 2000);
  };

  const scheduleDelete = async () => {
    if (deleteWord !== "delete") return;
    const scheduledDate = new Date();
    scheduledDate.setDate(scheduledDate.getDate() + 30);
    const updated = { ...user, deleteScheduled: scheduledDate.toISOString() };
    onUpdate(updated);
    setDeleteScheduled(scheduledDate.toISOString());
    setShowDelete(false);
    setDeleteWord("");

    // Ledgers this user owns that have other real members get locked for new
    // entries IMMEDIATELY (reusing the existing delete-request/countdown
    // mechanism — deleteScheduledAt alone is what triggers the lock via
    // `deleteLock` in LedgerDetail). Members get a 6-day window to save an
    // archived copy; no approval is required since this isn't optional —
    // it's a consequence of the account deletion, only the admin cancelling
    // the account deletion itself can undo it.
    const archiveDeadline = new Date();
    archiveDeadline.setDate(archiveDeadline.getDate() + 6);

    const ownedWithOthers = ledgers.filter((l) => {
      const isOwner = l.members[0]?.user_id === user.id;
      const hasOtherRealMembers = l.members.some(
        (m) => m.user_id && m.user_id !== user.id
      );
      return isOwner && hasOtherRealMembers && !l.archived && !l.deleteRequest;
    });

    for (const l of ownedWithOthers) {
      const deleteRequest = {
        initiated_at: now(),
        initiated_by: user.id,
        system_initiated: true, // triggered by account deletion, not a manual request
        consents: {},
        copyChoices: {},
      };
      const { error } = await sb
        .from("ledgers")
        .update({
          delete_request: deleteRequest,
          delete_scheduled_at: archiveDeadline.toISOString(),
        })
        .eq("id", l.id);
      if (error) {
        console.error("scheduleDelete: failed to lock ledger", l.id, error);
        continue;
      }
      const otherIds = l.members
        .filter((m) => m.user_id && m.user_id !== user.id)
        .map((m) => m.user_id);
      sendPushTo(
        otherIds,
        "Ledger locked — account being deleted",
        `${user.full_name || "The admin"}'s account is being deleted. "${l.name}" is now locked — you have 6 days to save an archived copy.`,
        l.name
      );
    }
    if (ownedWithOthers.length > 0 && onLedgersRefresh) onLedgersRefresh();
  };

  const cancelDelete = async () => {
    const updated = { ...user, deleteScheduled: null };
    onUpdate(updated);
    setDeleteScheduled(null);

    // Unlock any ledgers this account-deletion had locked, as long as their
    // own 6-day window hasn't already run out and executed.
    const lockedBySelf = ledgers.filter(
      (l) =>
        l.deleteRequest?.system_initiated &&
        l.deleteRequest?.initiated_by === user.id
    );
    for (const l of lockedBySelf) {
      const { error } = await sb
        .from("ledgers")
        .update({ delete_request: null, delete_scheduled_at: null })
        .eq("id", l.id);
      if (error)
        console.error("cancelDelete: failed to unlock ledger", l.id, error);
    }
    if (lockedBySelf.length > 0 && onLedgersRefresh) onLedgersRefresh();
  };

  const daysLeft = deleteScheduled
    ? Math.ceil(
        (new Date(deleteScheduled) - new Date()) / (1000 * 60 * 60 * 24)
      )
    : null;

  const renderAvatar = (size = 72) => {
    const av = AVATARS.find((a) => a.id === selectedAvatar);
    if (av)
      return (
        <img
          src={av.src}
          alt={av.label}
          style={{
            width: size,
            height: size,
            borderRadius: "16px",
            objectFit: "contain",
            background: "white",
            flexShrink: 0,
          }}
        />
      );
    return withPlanDot(
      <div
        style={{
          width: size,
          height: size,
          borderRadius: "20px",
          background: "linear-gradient(135deg,var(--accent),#7c3aed)",
          color: "white",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontSize: size * 0.35,
          fontWeight: "800",
          flexShrink: 0,
        }}
      >
        {initials(user.full_name)}
      </div>,
      user.plan
    );
  };

  return (
    <div
      className="modal-overlay"
      
    >
      <div className="modal" style={{ maxWidth: "420px" }}>
        <div className="modal-header">
          <h2>My Profile</h2>
          <button className="btn-icon" onClick={onClose}>
            <Icon.X />
          </button>
        </div>
        <div className="modal-body">
          {/* Avatar section */}
          <div
            style={{
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              marginBottom: "22px",
              gap: "10px",
            }}
          >
            {renderAvatar(72)}
            <div style={{ display: "flex", alignItems: "center", gap: "8px" }}>
              <span
                style={{
                  fontSize: "12px",
                  fontWeight: "700",
                  background: plan.bg,
                  color: plan.color,
                  padding: "3px 12px",
                  borderRadius: "20px",
                  border: `1px solid ${plan.color}44`,
                }}
              >
                {plan.name} plan
              </span>
              <button
                className="btn btn-secondary"
                style={{ fontSize: "11px", padding: "3px 12px" }}
                onClick={() => {
                  onClose();
                  onShowUpgrade && onShowUpgrade();
                }}
              >
                {plan.id === "gold" ? "View plans" : "Upgrade"}
              </button>
            </div>
            <button
              className="btn btn-secondary"
              style={{ fontSize: "12px", padding: "6px 14px" }}
              onClick={() => setShowAvatarPicker(!showAvatarPicker)}
            >
              {showAvatarPicker ? "Close" : "Change avatar"}
            </button>
          </div>

          {/* Push notifications */}
          <div
            style={{
              marginBottom: "20px",
              background: "var(--bg)",
              borderRadius: "var(--radius-sm)",
              padding: "14px",
              border: "1.5px solid var(--border)",
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              gap: "10px",
            }}
          >
            <div>
              <div style={{ fontSize: "13px", fontWeight: "700" }}>
                Notifications
              </div>
              <div style={{ fontSize: "12px", color: "var(--text2)" }}>
                {pushStatus === "granted"
                  ? "Enabled on this device."
                  : pushStatus === "denied"
                  ? "Blocked — enable in your browser's site settings."
                  : pushStatus === "unsupported"
                  ? "Not supported in this browser."
                  : pushStatus === "enabling"
                  ? "Enabling…"
                  : "Get notified about new expenses, approvals, and delete requests."}
              </div>
            </div>
            {pushStatus === "default" && (
              <button
                className="btn btn-secondary"
                style={{
                  fontSize: "12px",
                  padding: "6px 14px",
                  whiteSpace: "nowrap",
                }}
                onClick={handleEnablePush}
              >
                Enable
              </button>
            )}
            {pushStatus === "enabling" && (
              <button
                className="btn btn-secondary"
                style={{
                  fontSize: "12px",
                  padding: "6px 14px",
                  whiteSpace: "nowrap",
                }}
                disabled
              >
                Enabling…
              </button>
            )}
          </div>

          {/* Avatar picker */}
          {showAvatarPicker && (
            <div
              style={{
                marginBottom: "20px",
                background: "var(--bg)",
                borderRadius: "var(--radius-sm)",
                padding: "14px",
                border: "1.5px solid var(--border)",
              }}
            >
              <div
                style={{
                  display: "flex",
                  gap: "10px",
                  flexWrap: "wrap",
                  justifyContent: "center",
                }}
              >
                {AVATARS.map((av) => (
                  <img
                    key={av.id}
                    src={av.src}
                    alt={av.label}
                    onClick={() => {
                      setSelectedAvatar(av.id);
                      setShowAvatarPicker(false);
                    }}
                    style={{
                      width: "72px",
                      height: "72px",
                      cursor: "pointer",
                      border:
                        selectedAvatar === av.id
                          ? "3px solid var(--accent)"
                          : "3px solid transparent",
                      borderRadius: "14px",
                      objectFit: "contain",
                      transition: "all 0.15s",
                      display: "block",
                      background: "white",
                    }}
                  />
                ))}
              </div>
              {selectedAvatar && (
                <div style={{ textAlign: "center", marginTop: "10px" }}>
                  <button
                    className="btn btn-secondary"
                    style={{ fontSize: "11px", padding: "4px 10px" }}
                    onClick={() => setSelectedAvatar(null)}
                  >
                    Reset to initials
                  </button>
                </div>
              )}
              <div
                style={{
                  borderTop: "1px solid var(--border)",
                  marginTop: "12px",
                  paddingTop: "12px",
                }}
              >
                <PersonalAvatarCTA user={user} userPlan={plan} />
              </div>
            </div>
          )}

          <div className="form-group">
            <label>Full name</label>
            <input value={name} onChange={(e) => setName(e.target.value)} />
          </div>
          <div className="form-group">
            <label>Email</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label>Date of birth</label>
            <input
              type="date"
              value={dob}
              onChange={(e) => setDob(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label>Currency</label>
            <CurrencySearch
              currency={currency}
              currencies={currencies}
              onSelect={(c) => {
                onCurrencyChange && onCurrencyChange(c);
              }}
            />
            <p className="tip" style={{ marginTop: "4px" }}>
              Auto-detected from your location. Type a country or currency code.
            </p>
          </div>
          {saved && (
            <div
              style={{
                background: "var(--success-light)",
                border: "1px solid #a7f3d0",
                borderRadius: "var(--radius-sm)",
                padding: "10px 14px",
                fontSize: "13px",
                color: "var(--success)",
                fontWeight: "600",
                marginBottom: "8px",
              }}
            >
              Changes saved
            </div>
          )}

          {/* Change password */}
          <div
            style={{
              borderTop: "1px solid var(--border)",
              paddingTop: "14px",
              marginTop: "4px",
              marginBottom: "8px",
            }}
          >
            <button
              className="btn btn-secondary"
              style={{ width: "100%", fontSize: "13px" }}
              onClick={() => setShowPwdSection((p) => !p)}
            >
              {showPwdSection ? "Hide password" : "Change password"}
            </button>
            {showPwdSection && (
              <div
                style={{
                  marginTop: "10px",
                  display: "flex",
                  flexDirection: "column",
                  gap: "8px",
                }}
              >
                <div style={{ position: "relative" }}>
                  <input
                    type={showPwd ? "text" : "password"}
                    placeholder="Current password"
                    value={pwdCurrent}
                    onChange={(e) => setPwdCurrent(e.target.value)}
                    style={{
                      width: "100%",
                      padding: "10px 40px 10px 12px",
                      border: "1.5px solid var(--border)",
                      borderRadius: "var(--radius-sm)",
                      fontFamily: "var(--font)",
                      fontSize: "13px",
                      outline: "none",
                    }}
                  />
                  <button
                    type="button"
                    onClick={() => setShowPwd((p) => !p)}
                    style={{
                      position: "absolute",
                      right: "10px",
                      top: "50%",
                      transform: "translateY(-50%)",
                      background: "none",
                      border: "none",
                      cursor: "pointer",
                      fontSize: "11px",
                      fontWeight: "600",
                      color: "var(--text3)",
                      fontFamily: "var(--font)",
                    }}
                  >
                    {showPwd ? "Hide" : "Show"}
                  </button>
                </div>
                <input
                  type={showPwd ? "text" : "password"}
                  placeholder="New password"
                  value={pwdNew}
                  onChange={(e) => setPwdNew(e.target.value)}
                  style={{
                    width: "100%",
                    padding: "10px 12px",
                    border: "1.5px solid var(--border)",
                    borderRadius: "var(--radius-sm)",
                    fontFamily: "var(--font)",
                    fontSize: "13px",
                    outline: "none",
                  }}
                />
                <input
                  type={showPwd ? "text" : "password"}
                  placeholder="Confirm new password"
                  value={pwdNew2}
                  onChange={(e) => setPwdNew2(e.target.value)}
                  style={{
                    width: "100%",
                    padding: "10px 12px",
                    border: "1.5px solid var(--border)",
                    borderRadius: "var(--radius-sm)",
                    fontFamily: "var(--font)",
                    fontSize: "13px",
                    outline: "none",
                  }}
                />
                {pwdMsg && (
                  <div
                    style={{
                      fontSize: "12px",
                      color: pwdMsg.startsWith("Password changed")
                        ? "var(--success)"
                        : "var(--danger)",
                      fontWeight: 600,
                    }}
                  >
                    {pwdMsg}
                  </div>
                )}
                <button
                  className="btn btn-primary"
                  style={{ fontSize: "13px" }}
                  onClick={changePassword}
                >
                  Update password
                </button>
              </div>
            )}
          </div>

          {/* Deletion scheduled banner */}
          {deleteScheduled && daysLeft > 0 && (
            <div
              style={{
                background: "#fff7ed",
                border: "2px solid #fed7aa",
                borderRadius: "var(--radius-sm)",
                padding: "12px 14px",
                marginBottom: "10px",
                display: "flex",
                alignItems: "center",
                gap: "10px",
              }}
            >
              <div style={{ flex: 1 }}>
                <div
                  style={{
                    fontSize: "13px",
                    fontWeight: "700",
                    color: "#c2410c",
                  }}
                >
                  Account deletion in {daysLeft} days
                </div>
                <div
                  style={{
                    fontSize: "11px",
                    color: "#9a3412",
                    marginTop: "2px",
                  }}
                >
                  Your account and all data will be permanently deleted.
                </div>
              </div>
              <button
                className="btn btn-secondary"
                style={{
                  fontSize: "12px",
                  padding: "6px 12px",
                  whiteSpace: "nowrap",
                }}
                onClick={cancelDelete}
              >
                Cancel
              </button>
            </div>
          )}

          {/* Sign out + Delete */}
          <div
            style={{
              borderTop: "1px solid var(--border)",
              paddingTop: "14px",
              marginTop: "4px",
              display: "flex",
              flexDirection: "column",
              gap: "8px",
            }}
          >
            <button
              className="btn"
              style={{
                width: "100%",
                background: "var(--danger-light)",
                color: "var(--danger)",
                border: "1.5px solid #fca5a5",
                fontSize: "13px",
              }}
              onClick={() => {
                onLogout();
                onClose();
              }}
            >
              <Icon.LogOut /> Sign out
            </button>
            {!deleteScheduled && (
              <button
                className="btn btn-secondary"
                style={{
                  width: "100%",
                  fontSize: "12px",
                  color: "var(--danger)",
                  borderColor: "#fca5a5",
                }}
                onClick={() => setShowDelete(true)}
              >
                Delete my account permanently
              </button>
            )}
          </div>

          {/* Delete confirmation modal */}
          {showDelete && (
            <div
              className="modal-overlay"
            >
              <div className="modal" style={{ maxWidth: "380px" }}>
                <div className="modal-header">
                  <h2>Delete account</h2>
                  <button
                    className="btn-icon"
                    onClick={() => setShowDelete(false)}
                  >
                    <Icon.X />
                  </button>
                </div>
                <div className="modal-body">
                  <div
                    style={{
                      background: "var(--danger-light)",
                      border: "1.5px solid #fca5a5",
                      borderRadius: "var(--radius-sm)",
                      padding: "12px 14px",
                      marginBottom: "16px",
                      fontSize: "13px",
                      color: "var(--danger)",
                      lineHeight: 1.6,
                    }}
                  >
                    <strong>
                      Your account will be permanently deleted in 30 days.
                    </strong>{" "}
                    You can cancel within that period. After 30 days all your
                    data is gone forever.
                  </div>
                  <div
                    style={{
                      fontSize: "13px",
                      fontWeight: "600",
                      color: "var(--text)",
                      marginBottom: "8px",
                    }}
                  >
                    What happens to your ledgers?
                  </div>
                  <div
                    style={{
                      fontSize: "12px",
                      color: "var(--text2)",
                      display: "flex",
                      alignItems: "flex-start",
                      gap: "8px",
                      padding: "8px 10px",
                      background: "var(--bg)",
                      borderRadius: "var(--radius-sm)",
                      marginBottom: "8px",
                    }}
                  >
                    <span style={{ marginRight: "6px", color: "var(--text3)" }}>
                      -
                    </span>
                    <div>
                      <strong>If you're the only real member</strong> - the
                      ledger is permanently deleted along with everything in
                      it.
                    </div>
                  </div>
                  <div
                    style={{
                      fontSize: "12px",
                      color: "var(--text2)",
                      display: "flex",
                      alignItems: "flex-start",
                      gap: "8px",
                      padding: "8px 10px",
                      background: "var(--bg)",
                      borderRadius: "var(--radius-sm)",
                      marginBottom: "8px",
                    }}
                  >
                    <span style={{ marginRight: "6px", color: "var(--text3)" }}>
                      -
                    </span>
                    <div>
                      <strong>If you're admin and others are in it</strong> -
                      they're notified now so they have the full 30 days to
                      save an archived copy. The ledger isn't deleted — it
                      continues for them, you just won't be part of it anymore.
                    </div>
                  </div>
                  <div
                    style={{
                      fontSize: "12px",
                      color: "var(--text2)",
                      display: "flex",
                      alignItems: "flex-start",
                      gap: "8px",
                      padding: "8px 10px",
                      background: "var(--bg)",
                      borderRadius: "var(--radius-sm)",
                      marginBottom: "16px",
                    }}
                  >
                    <span style={{ marginRight: "6px", color: "var(--text3)" }}>
                      -
                    </span>
                    <div>
                      <strong>If you are just a member</strong> - the ledger
                      stays, but your name will show as having no account.
                    </div>
                  </div>
                  <div className="form-group">
                    <label style={{ color: "var(--danger)" }}>
                      Type <strong>delete</strong> to confirm
                    </label>
                    <input
                      placeholder="delete"
                      value={deleteWord}
                      onChange={(e) =>
                        setDeleteWord(e.target.value.toLowerCase())
                      }
                      style={{
                        borderColor:
                          deleteWord && deleteWord !== "delete"
                            ? "var(--danger)"
                            : "var(--border)",
                      }}
                    />
                  </div>
                </div>
                <div className="modal-footer">
                  <button
                    className="btn btn-secondary"
                    onClick={() => {
                      setShowDelete(false);
                      setDeleteWord("");
                    }}
                  >
                    Cancel
                  </button>
                  <button
                    className="btn"
                    style={{
                      background: "var(--danger)",
                      color: "white",
                      opacity: deleteWord === "delete" ? 1 : 0.4,
                      cursor:
                        deleteWord === "delete" ? "pointer" : "not-allowed",
                    }}
                    onClick={scheduleDelete}
                    disabled={deleteWord !== "delete"}
                  >
                    Schedule deletion
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
        <div className="modal-footer">
          <button className="btn btn-secondary" onClick={onClose}>
            Cancel
          </button>
          <button className="btn btn-primary" onClick={save}>
            Save changes
          </button>
        </div>
      </div>
    </div>
  );
}

